func (v RbacPermission) GoString() string {
	if s := v.openapiName(); s != "" {
		return "apitype.RbacPermission" + s
	}
	return fmt.Sprintf("apitype.RbacPermission(%#v)", string(v))
}

func (v *RbacPermission) UnmarshalJSON(bytes []byte) error {
	var raw string
	if err := json.Unmarshal(bytes, &raw); err != nil {
		return err
	}

	typed := RbacPermission(raw)
	if !typed.IsValid() {
		var typedEmpty RbacPermission
		typed = typedEmpty
	}

	*v = typed
	return nil
}

type RbacPermissionSlice []RbacPermission

func (v *RbacPermissionSlice) UnmarshalJSON(bytes []byte) error {
	var rawList []string
	if err := json.Unmarshal(bytes, &rawList); err != nil {
		return err
	}

	typedList := RbacPermissionSlice{}
	for _, raw := range rawList {
		typed := RbacPermission(raw)
		if typed.IsValid() {
			typedList = append(typedList, typed)
		}
	}

	*v = typedList
	return nil
}
